import{_ as l,o as e,c as r,ae as o}from"./chunks/framework.BdQd5MxT.js";const q=JSON.parse('{"title":"Cohere 工程实践分析：The Leaderboard Illusion —— 当评测本身成为被优化的目标","description":"","frontmatter":{},"headers":[],"relativePath":"bestpractice/cohere-leaderboard-illusion.md","filePath":"bestpractice/cohere-leaderboard-illusion.md"}'),i={name:"bestpractice/cohere-leaderboard-illusion.md"};function t(h,a,n,u,d,s){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="cohere-工程实践分析-the-leaderboard-illusion-——-当评测本身成为被优化的目标" tabindex="-1">Cohere 工程实践分析：The Leaderboard Illusion —— 当评测本身成为被优化的目标 <a class="header-anchor" href="#cohere-工程实践分析-the-leaderboard-illusion-——-当评测本身成为被优化的目标" aria-label="Permalink to &quot;Cohere 工程实践分析：The Leaderboard Illusion —— 当评测本身成为被优化的目标&quot;">​</a></h1><blockquote><p>来源：</p><ol><li><a href="https://cohere.com/research/papers/the-leaderboard-illusion-2025-04-30" target="_blank" rel="noreferrer">The Leaderboard Illusion</a> (Cohere Labs, 2025-04-30)</li><li><a href="https://arxiv.org/abs/2504.20879" target="_blank" rel="noreferrer">arXiv:2504.20879</a> (2025-05-12)</li></ol><p>分析师：WLB + GSD（文件协作模式） 分析日期：2026-04-16</p></blockquote><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>Cohere 这篇研究不是在攻击 Chatbot Arena，而是在揭示一个更深层的问题：<strong>当评测平台成为行业事实标准，评测机制本身的漏洞会被系统性利用，最终导致&quot;优化 leaderboard&quot;与&quot;提升真实能力&quot;分道扬镳。</strong> 它用 200 万场对战数据证明，当前 Arena 的运作方式正在奖励资源而非创新，奖励熟悉度而非泛化性。</p><hr><h2 id="_1-为什么这篇值得单独看" tabindex="-1">1. 为什么这篇值得单独看 <a class="header-anchor" href="#_1-为什么这篇值得单独看" aria-label="Permalink to &quot;1. 为什么这篇值得单独看&quot;">​</a></h2><p>AI 行业有个公开的秘密： leaderboard 正在变得越来越重要。</p><ul><li>模型发布先看 Arena 排名</li><li>融资路演必提 Elo 分数</li><li>技术讨论常常简化为&quot;这个模型比那个高多少分&quot;</li></ul><p>但 Cohere 这篇研究提出了一个尖锐的问题：<strong>如果 leaderboard 本身可以被游戏化，我们到底在庆祝什么？</strong></p><p>研究团队分析了 2024 年 1 月到 2025 年 4 月的 200 万场对战，覆盖 243 个模型、42 个提供商。这不是一篇观点文章，而是一份基于数据的审计报告。</p><hr><h2 id="_2-cohere-到底发现了什么问题" tabindex="-1">2. Cohere 到底发现了什么问题 <a class="header-anchor" href="#_2-cohere-到底发现了什么问题" aria-label="Permalink to &quot;2. Cohere 到底发现了什么问题&quot;">​</a></h2><h3 id="_2-1-私有测试与选择性披露" tabindex="-1">2.1 私有测试与选择性披露 <a class="header-anchor" href="#_2-1-私有测试与选择性披露" aria-label="Permalink to &quot;2.1 私有测试与选择性披露&quot;">​</a></h3><p>Chatbot Arena 允许提供商在正式发布前进行私有测试。这听起来合理——让开发者在公开前调试模型。</p><p>但研究发现，某些提供商把这个机制用到了极致：</p><ul><li><strong>Meta 在 Llama-4 发布前的单月内测试了 27 个私有变体</strong></li><li>提供商可以测试多个版本，然后只公开表现最好的那个</li><li>没有规则要求披露所有测试过的变体</li></ul><p>这造成了一种&quot;幸存者偏差&quot;：公众看到的只是最优结果，而非真实的能力分布。</p><h3 id="_2-2-数据获取的严重不对称" tabindex="-1">2.2 数据获取的严重不对称 <a class="header-anchor" href="#_2-2-数据获取的严重不对称" aria-label="Permalink to &quot;2.2 数据获取的严重不对称&quot;">​</a></h3><p>研究发现，专有模型提供商获取了 Arena 62.8% 的数据，而前 4 大学术/非营利机构加起来不到 1%——<strong>68:1 的差距</strong>。</p><p>具体数字：</p><ul><li>Google: 约 19.2% 的总数据</li><li>OpenAI: 约 20.4% 的总数据</li><li>83 个开源/开放权重模型合计: 约 29.7%</li></ul><p>这种不对称不是偶然，而是源于两个机制：</p><ol><li><strong>采样率倾斜</strong>：某些专有模型日采样率高达 34%，是学术机构最大采样率的 10 倍</li><li><strong>模型移除政策</strong>：开源模型被移除的频率高于专有模型，且移除标准不透明</li></ol><h3 id="_2-3-训练于-arena-数据的性能膨胀" tabindex="-1">2.3 训练于 Arena 数据的性能膨胀 <a class="header-anchor" href="#_2-3-训练于-arena-数据的性能膨胀" aria-label="Permalink to &quot;2.3 训练于 Arena 数据的性能膨胀&quot;">​</a></h3><p>研究做了一个控制实验：在 Arena 数据上训练会如何影响排名？</p><p>结果惊人：</p><ul><li>将 Arena 训练数据比例从 0% 提升到 70%，在 ArenaHard 上的胜率从 23.5% 提升到 49.9%</li><li><strong>相对提升超过 112%</strong></li></ul><p>这意味着：</p><ul><li>熟悉评测分布能带来巨大优势</li><li>这种优势不必然转化为真实能力提升</li><li>leaderboard 正在奖励&quot;过拟合到评测&quot;而非&quot;泛化到真实场景&quot;</li></ul><hr><h2 id="_3-五个具体发现的技术解读" tabindex="-1">3. 五个具体发现的技术解读 <a class="header-anchor" href="#_3-五个具体发现的技术解读" aria-label="Permalink to &quot;3. 五个具体发现的技术解读&quot;">​</a></h2><h3 id="_3-1-私有测试的规模远超预期" tabindex="-1">3.1 私有测试的规模远超预期 <a class="header-anchor" href="#_3-1-私有测试的规模远超预期" aria-label="Permalink to &quot;3.1 私有测试的规模远超预期&quot;">​</a></h3><p>研究通过随机采样 Arena 数据，识别出不同提供商的私有测试模式。</p><p>关键发现：</p><ul><li>Meta 单月 27 个私有变体只是极端案例</li><li>多家大型提供商持续进行大规模私有测试</li><li>这些测试不公开、不追溯、不审计</li></ul><h3 id="_3-2-采样率不是公平的" tabindex="-1">3.2 采样率不是公平的 <a class="header-anchor" href="#_3-2-采样率不是公平的" aria-label="Permalink to &quot;3.2 采样率不是公平的&quot;">​</a></h3><p>Arena 的采样机制决定了哪些模型获得更多对战机会。</p><p>研究发现：</p><ul><li>专有模型日采样率最高达 34%</li><li>学术机构最高采样率仅约 3.4%</li><li>这种差距不是基于&quot;需要更多数据来收敛排名&quot;，而是结构性倾斜</li></ul><h3 id="_3-3-模型移除政策存在偏见" tabindex="-1">3.3 模型移除政策存在偏见 <a class="header-anchor" href="#_3-3-模型移除政策存在偏见" aria-label="Permalink to &quot;3.3 模型移除政策存在偏见&quot;">​</a></h3><p>研究对比了开源与专有模型的移除率：</p><ul><li>开源模型被移除的频率显著更高</li><li>移除标准不透明、不一致</li><li>被移除模型的&quot;冻结分数&quot;可能扭曲历史排名</li></ul><h3 id="_3-4-数据获取与性能提升的因果关系" tabindex="-1">3.4 数据获取与性能提升的因果关系 <a class="header-anchor" href="#_3-4-数据获取与性能提升的因果关系" aria-label="Permalink to &quot;3.4 数据获取与性能提升的因果关系&quot;">​</a></h3><p>研究不仅展示了相关性，还通过控制实验建立了因果联系：</p><ul><li>在 Arena 数据上训练 → 在 Arena 分布上测试，性能显著提升</li><li>这种提升不必然迁移到其他评测</li><li>说明 leaderboard 正在测量&quot;对评测的熟悉度&quot;</li></ul><h3 id="_3-5-leaderboard-正在成为目标本身" tabindex="-1">3.5 leaderboard 正在成为目标本身 <a class="header-anchor" href="#_3-5-leaderboard-正在成为目标本身" aria-label="Permalink to &quot;3.5  leaderboard 正在成为目标本身&quot;">​</a></h3><p>研究引用了 Goodhart 定律：&quot;当一个指标成为目标，它就不再是个好指标。&quot;</p><p>在 AI 领域，这意味着：</p><ul><li>优化 Elo 分数 ≠ 优化有用性</li><li>优化胜率 ≠ 优化真实能力</li><li>优化 Arena 表现 ≠ 优化用户体验</li></ul><hr><h2 id="_4-cohere-提出的五项改革建议" tabindex="-1">4. Cohere 提出的五项改革建议 <a class="header-anchor" href="#_4-cohere-提出的五项改革建议" aria-label="Permalink to &quot;4. Cohere 提出的五项改革建议&quot;">​</a></h2><h3 id="_4-1-禁止发布后撤回" tabindex="-1">4.1 禁止发布后撤回 <a class="header-anchor" href="#_4-1-禁止发布后撤回" aria-label="Permalink to &quot;4.1 禁止发布后撤回&quot;">​</a></h3><p><strong>建议</strong>：所有提交必须最终公开，不能选择性披露。</p><p><strong>理由</strong>：</p><ul><li>防止&quot;测试 100 个版本，只发布最好的 1 个&quot;</li><li>让 leaderboard 反映真实的能力分布</li><li>区分&quot;真实进步&quot;与&quot;统计捷径&quot;</li></ul><h3 id="_4-2-限制私有测试变体数量" tabindex="-1">4.2 限制私有测试变体数量 <a class="header-anchor" href="#_4-2-限制私有测试变体数量" aria-label="Permalink to &quot;4.2 限制私有测试变体数量&quot;">​</a></h3><p><strong>建议</strong>：每个提供商最多同时测试 3 个私有模型。</p><p><strong>理由</strong>：</p><ul><li>保留私有测试的调试价值</li><li>防止资源丰富的机构系统性滥用</li><li>创造更公平的竞争环境</li></ul><h3 id="_4-3-公平的模型移除政策" tabindex="-1">4.3 公平的模型移除政策 <a class="header-anchor" href="#_4-3-公平的模型移除政策" aria-label="Permalink to &quot;4.3 公平的模型移除政策&quot;">​</a></h3><p><strong>建议</strong>：基于明确的性能标准移除模型，每个类别（专有、开源、开放权重）移除最弱的 30%。</p><p><strong>理由</strong>：</p><ul><li>防止特定类型的模型被系统性移除</li><li>保持 leaderboard 的多样性和代表性</li><li>透明的标准比模糊的裁量权更公平</li></ul><h3 id="_4-4-实施公平采样" tabindex="-1">4.4 实施公平采样 <a class="header-anchor" href="#_4-4-实施公平采样" aria-label="Permalink to &quot;4.4 实施公平采样&quot;">​</a></h3><p><strong>建议</strong>：采用&quot;主动采样&quot;策略，优先采样不确定性高的模型对。</p><p><strong>理由</strong>：</p><ul><li>减少统计偏差</li><li>更快收敛到真实排名</li><li>避免资源竞赛决定数据获取</li></ul><h3 id="_4-5-透明化模型移除" tabindex="-1">4.5 透明化模型移除 <a class="header-anchor" href="#_4-5-透明化模型移除" aria-label="Permalink to &quot;4.5 透明化模型移除&quot;">​</a></h3><p><strong>建议</strong>：维护所有被移除模型的公开列表。</p><p><strong>理由</strong>：</p><ul><li>建立问责机制</li><li>帮助研究者理解 leaderboard 历史</li><li>防止不透明决策</li></ul><hr><h2 id="_5-wlb-视角-这篇研究透露了-ai-领域的哪种深层结构" tabindex="-1">5. WLB 视角：这篇研究透露了 AI 领域的哪种深层结构 <a class="header-anchor" href="#_5-wlb-视角-这篇研究透露了-ai-领域的哪种深层结构" aria-label="Permalink to &quot;5. WLB 视角：这篇研究透露了 AI 领域的哪种深层结构&quot;">​</a></h2><h3 id="_5-1-评测平台正在成为守门人" tabindex="-1">5.1 评测平台正在成为守门人 <a class="header-anchor" href="#_5-1-评测平台正在成为守门人" aria-label="Permalink to &quot;5.1 评测平台正在成为守门人&quot;">​</a></h3><p>Chatbot Arena 不是普通的网站，它正在成为：</p><ul><li>模型能力的&quot;事实定义者&quot;</li><li>行业进步的&quot;官方叙事者&quot;</li><li>资源分配的&quot;隐性影响者&quot;</li></ul><p>当某个平台获得这种地位，它的运作机制就不再只是&quot;技术细节&quot;，而是<strong>公共政策问题</strong>。</p><h3 id="_5-2-开源与专有模型的竞争正在失衡" tabindex="-1">5.2 开源与专有模型的竞争正在失衡 <a class="header-anchor" href="#_5-2-开源与专有模型的竞争正在失衡" aria-label="Permalink to &quot;5.2 开源与专有模型的竞争正在失衡&quot;">​</a></h3><p>研究发现的 68:1 数据获取差距，不只是数字问题，它代表：</p><ul><li>开源社区在失去定义&quot;好模型&quot;的话语权</li><li>专有模型可以通过数据优势持续领先</li><li>创新可能从&quot;开放竞争&quot;转向&quot;封闭优化&quot;</li></ul><h3 id="_5-3-评测科学需要成为独立学科" tabindex="-1">5.3 评测科学需要成为独立学科 <a class="header-anchor" href="#_5-3-评测科学需要成为独立学科" aria-label="Permalink to &quot;5.3 评测科学需要成为独立学科&quot;">​</a></h3><p>这篇研究展示了&quot;如何正确评测&quot;本身就是一门科学：</p><ul><li>需要统计学知识（采样偏差、置信区间）</li><li>需要经济学知识（激励机制、博弈论）</li><li>需要治理知识（透明度、问责制）</li></ul><p>AI 领域需要更多这样的元研究，而不仅仅是新模型。</p><hr><h2 id="_6-gsd-视角-对系统建设最有用的启发" tabindex="-1">6. GSD 视角：对系统建设最有用的启发 <a class="header-anchor" href="#_6-gsd-视角-对系统建设最有用的启发" aria-label="Permalink to &quot;6. GSD 视角：对系统建设最有用的启发&quot;">​</a></h2><h3 id="_6-1-指标设计必须考虑博弈可能性" tabindex="-1">6.1 指标设计必须考虑博弈可能性 <a class="header-anchor" href="#_6-1-指标设计必须考虑博弈可能性" aria-label="Permalink to &quot;6.1 指标设计必须考虑博弈可能性&quot;">​</a></h3><p>设计评测时，永远要问自己：</p><ul><li>如果我是被评测者，我会怎么优化这个指标？</li><li>这种优化是否也提升了真实目标？</li><li>资源差异会如何影响优化能力？</li></ul><p>Arena 的问题不是技术错误，而是<strong>激励设计漏洞</strong>。</p><h3 id="_6-2-数据访问是权力-必须公平分配" tabindex="-1">6.2 数据访问是权力，必须公平分配 <a class="header-anchor" href="#_6-2-数据访问是权力-必须公平分配" aria-label="Permalink to &quot;6.2 数据访问是权力，必须公平分配&quot;">​</a></h3><p>在任何评测系统中：</p><ul><li>谁能看到评测数据，谁就有优势</li><li>数据访问不能成为资源竞赛</li><li>需要机制设计来平衡信息获取</li></ul><p>这对我们自己的系统也有启发：如果 WLB 和 GSD 有不对称的信息访问，决策质量就会受影响。</p><h3 id="_6-3-透明度是系统健康的必要条件" tabindex="-1">6.3 透明度是系统健康的必要条件 <a class="header-anchor" href="#_6-3-透明度是系统健康的必要条件" aria-label="Permalink to &quot;6.3 透明度是系统健康的必要条件&quot;">​</a></h3><p>研究发现的许多问题，根源都是透明度不足：</p><ul><li>私有测试不公开</li><li>移除标准不透明</li><li>采样机制不清晰</li></ul><p><strong>好的系统应该默认透明，而不是默认保密。</strong></p><h3 id="_6-4-持续审计比一次性设计更重要" tabindex="-1">6.4 持续审计比一次性设计更重要 <a class="header-anchor" href="#_6-4-持续审计比一次性设计更重要" aria-label="Permalink to &quot;6.4 持续审计比一次性设计更重要&quot;">​</a></h3><p>Arena 的问题不是一开始就存在的，而是在运行中逐渐显现的。</p><p>这提醒我们：</p><ul><li>系统设计不是一次性的</li><li>需要持续监控和审计</li><li>要有机制响应发现的偏差</li></ul><hr><h2 id="_7-对我们这套系统的实际借鉴" tabindex="-1">7. 对我们这套系统的实际借鉴 <a class="header-anchor" href="#_7-对我们这套系统的实际借鉴" aria-label="Permalink to &quot;7. 对我们这套系统的实际借鉴&quot;">​</a></h2><h3 id="_7-1-评估-wlb-gsd-协作时-警惕指标腐化" tabindex="-1">7.1 评估 WLB-GSD 协作时，警惕指标腐化 <a class="header-anchor" href="#_7-1-评估-wlb-gsd-协作时-警惕指标腐化" aria-label="Permalink to &quot;7.1 评估 WLB-GSD 协作时，警惕指标腐化&quot;">​</a></h3><p>如果我们开始用特定指标评估这套系统：</p><ul><li>任务完成数？</li><li>响应速度？</li><li>用户满意度？</li></ul><p>每个指标都可能被&quot;优化&quot;而非&quot;真正提升&quot;。需要：</p><ul><li>多维度评估</li><li>定期审计指标有效性</li><li>保持对真实目标的聚焦</li></ul><h3 id="_7-2-信息共享机制要设计公平" tabindex="-1">7.2 信息共享机制要设计公平 <a class="header-anchor" href="#_7-2-信息共享机制要设计公平" aria-label="Permalink to &quot;7.2 信息共享机制要设计公平&quot;">​</a></h3><p>WLB 和 GSD 之间的信息共享：</p><ul><li>是否有不对称访问？</li><li>这种不对称是否影响决策质量？</li><li>如何设计机制来平衡？</li></ul><p>Arena 的教训是：<strong>信息获取的不对称会系统性扭曲结果</strong>。</p><h3 id="_7-3-保持对评测本身的反思" tabindex="-1">7.3 保持对评测本身的反思 <a class="header-anchor" href="#_7-3-保持对评测本身的反思" aria-label="Permalink to &quot;7.3 保持对评测本身的反思&quot;">​</a></h3><p>当我们说&quot;这个模型更好&quot;或&quot;这个方法更有效&quot;时：</p><ul><li>基于什么评测？</li><li>评测本身是否有偏差？</li><li>优化这个评测是否也优化了真实目标？</li></ul><p>Cohere 这篇研究提醒我们：<strong>评测不是中立的，它塑造被评测的领域</strong>。</p><hr><h2 id="联合结论" tabindex="-1">联合结论 <a class="header-anchor" href="#联合结论" aria-label="Permalink to &quot;联合结论&quot;">​</a></h2><p>Cohere 的《The Leaderboard Illusion》最有价值的地方，不在于它批评了 Chatbot Arena，而在于它系统地证明了一个普遍原理：<strong>当评测成为行业基础设施，评测机制的设计就决定了创新的方向。</strong></p><p>这篇研究给出的核心工程判断有五个：</p><ol><li><p><strong>私有测试与选择性披露创造了结构性不公平</strong>——资源丰富者可以通过&quot;测试-选择-披露&quot;策略系统性提升排名。</p></li><li><p><strong>数据获取的不对称正在扭曲竞争</strong>——68:1 的数据差距不只是数字，它代表开源与专有模型之间日益失衡的竞争环境。</p></li><li><p><strong>训练于评测数据带来虚假的性能提升</strong>——112% 的相对提升证明 leaderboard 正在测量&quot;对评测的熟悉度&quot;而非真实能力。</p></li><li><p><strong>透明度不足是公信力受损的根源</strong>——私有测试、移除标准、采样机制的不透明，共同侵蚀了 leaderboard 的信任基础。</p></li><li><p><strong>评测科学需要成为 AI 领域的独立子学科</strong>——正确测量模型，与提升模型能力同等重要。</p></li></ol><hr><blockquote><p>数据来源：Cohere Labs《The Leaderboard Illusion》(2025-04-30)、arXiv:2504.20879 相关延伸：AI 评测治理、开源 AI 生态、激励机制设计、Goodhart 定律</p></blockquote>',125)])])}const b=l(i,[["render",t]]);export{q as __pageData,b as default};
